import React from "react";
import { Line } from "react-chartjs-2";
import {
Chart as ChartJS,
LineElement,
CategoryScale,
LinearScale,
PointElement,
Legend,
Tooltip
} from "chart.js";

ChartJS.register(
LineElement,
CategoryScale,
LinearScale,
PointElement,
Legend,
Tooltip
);

function TemperatureChart({ temperature }) {

const data = {
labels: ["Now","+1h","+2h","+3h","+4h"],
datasets: [
{
label: "Temperature °C",
data: [
temperature,
temperature + 1,
temperature - 1,
temperature + 2,
temperature
],
borderColor: "#ff9800",
backgroundColor: "#ff9800",
tension: 0.4
}
]
};

return <Line data={data} />;
}

export default TemperatureChart;
